// Units ordered so 'ms' is matched before 'm'.
const UNITS = [
  ['ms', 1],
  ['s', 1000],
  ['m', 60000],
  ['h', 3600000],
  ['d', 86400000],
];

function parseDuration(str) {
  if (typeof str !== 'string' || str.length === 0) {
    throw new Error(`parseDuration: invalid input: ${str}`);
  }

  // Bare integer (whole string, no unit) is milliseconds.
  if (/^\d+$/.test(str)) {
    return parseInt(str, 10);
  }

  let total = 0;
  let remaining = str;

  while (remaining.length > 0) {
    const numMatch = remaining.match(/^(\d+)/);
    if (!numMatch) {
      throw new Error(`parseDuration: unexpected character at: ${remaining}`);
    }
    const value = parseInt(numMatch[1], 10);
    remaining = remaining.slice(numMatch[1].length);

    let matched = false;
    for (const [unit, multiplier] of UNITS) {
      if (remaining.startsWith(unit)) {
        total += value * multiplier;
        remaining = remaining.slice(unit.length);
        matched = true;
        break;
      }
    }

    if (!matched) {
      throw new Error(`parseDuration: unknown or missing unit at: ${remaining}`);
    }
  }

  return total;
}

