const { parseDuration } = require('./src/core/duration.js');
const cases = [
  ['30s',    30000],
  ['5m',     300000],
  ['1000ms', 1000],
  ['2h',     7200000],
  ['1h30m',  5400000],
  ['500ms',  500],
  ['250',    250],
  ['1d',     86400000],
  ['1h30m15s', 5415000],
];
let ok = true;
for (const [input, expected] of cases) {
  const got = parseDuration(input);
  const pass = got === expected;
  console.log((pass ? 'PASS' : 'FAIL'), input, '->', got, pass ? '' : '(expected ' + expected + ')');
  if (!pass) ok = false;
}
// Error cases
try { parseDuration('abc'); console.log('FAIL: should throw on abc'); ok = false; } catch { console.log('PASS throws on abc'); }
try { parseDuration('');    console.log('FAIL: should throw on empty'); ok = false; } catch { console.log('PASS throws on empty'); }
try { parseDuration('1x');  console.log('FAIL: should throw on 1x'); ok = false;  } catch { console.log('PASS throws on 1x'); }
console.log(ok ? 'ALL PASS' : 'SOME FAILED');
